"use client";

import React, { useState, useEffect } from 'react';
import { Database, HardDrive, Server, Box, RefreshCw } from 'lucide-react';
import clsx from 'clsx';

// Shape of the /api/v1/health response
interface HealthData {
  status: string;
  dependencies: { redis?: string; [key: string]: string | undefined };
  uptime_seconds?: number;
  version?: string;
}

// Shape of the /api/v1/info response
interface InfoData {
  service: string;
  version: string;
  environment: string;
  redis: { enabled: boolean; stats: { connected_clients?: number; used_memory_mb?: number } };
  tracing: { enabled: boolean; exporter: string };
}

type ConnectionStatus = "loading" | "online" | "offline";

function StatusBadge({ status }: { status: ConnectionStatus }) {
  return (
    <span className={clsx(
      "text-xs font-medium px-1.5 py-0.5 rounded border",
      status === "online" ? "bg-emerald-500/10 text-emerald-400 border-emerald-500/20" :
      status === "offline" ? "bg-red-500/10 text-red-400 border-red-500/20" :
      "bg-slate-700/50 text-slate-400 border-slate-700"
    )}>
      {status === "loading" ? "Polling..." : status === "online" ? "Online" : "Offline"}
    </span>
  );
}

export default function SystemMetrics() {
  const [health, setHealth] = useState<HealthData | null>(null);
  const [info, setInfo] = useState<InfoData | null>(null);
  const [gatewayStatus, setGatewayStatus] = useState<ConnectionStatus>("loading");
  const [redisStatus, setRedisStatus] = useState<ConnectionStatus>("loading");
  const [lastUpdated, setLastUpdated] = useState<string>("");

  const apiUrl = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";

  const fetchMetrics = async () => {
    // Fetch /api/v1/health
    try {
      const res = await fetch(`${apiUrl}/api/v1/health`, { signal: AbortSignal.timeout(3000) });
      if (res.ok) {
        const data: HealthData = await res.json();
        setHealth(data);
        setGatewayStatus("online");
        setRedisStatus(data.dependencies?.redis === "healthy" ? "online" : "offline");
      } else {
        setGatewayStatus("offline");
      }
    } catch {
      setGatewayStatus("offline");
      setRedisStatus("offline");
    }

    // Fetch /api/v1/info
    try {
      const res = await fetch(`${apiUrl}/api/v1/info`, { signal: AbortSignal.timeout(3000) });
      if (res.ok) {
        const data: InfoData = await res.json();
        setInfo(data);
      }
    } catch {
      // Info endpoint unreachable, gracefully degrade
    }

    setLastUpdated(new Date().toLocaleTimeString());
  };

  // Initial fetch + 5-second polling interval
  useEffect(() => {
    fetchMetrics();
    const interval = setInterval(fetchMetrics, 5000);
    return () => clearInterval(interval);
  }, []);

  const redisMemory = info?.redis?.stats?.used_memory_mb
    ? `${info.redis.stats.used_memory_mb.toFixed(1)}MB`
    : "N/A";

  const redisClients = info?.redis?.stats?.connected_clients ?? "–";

  return (
    <div className="mb-6">
      <div className="flex items-center justify-between mb-3">
        <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">
          Infrastructure Metrics
        </h2>
        <div className="flex items-center gap-2 text-xs text-slate-500">
          <RefreshCw className={clsx("w-3 h-3", gatewayStatus === "loading" && "animate-spin")} />
          Last updated: {lastUpdated || "—"}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">

        {/* FastAPI Gateway Card */}
        <div className="bg-slate-900 border border-slate-800 rounded-lg p-4 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-16 h-16 bg-blue-500/5 rounded-bl-full -mr-4 -mt-4" />
          <div className="flex justify-between items-start mb-4 relative z-10">
            <div>
              <h3 className="text-sm font-medium text-slate-400">FastAPI Gateway</h3>
              <div className="flex items-center gap-2 mt-1">
                <span className="text-2xl font-bold text-slate-100">
                  {info?.service ?? "—"}
                </span>
              </div>
              <div className="mt-1">
                <StatusBadge status={gatewayStatus} />
              </div>
            </div>
            <div className="p-2 bg-blue-500/10 rounded-md">
              <Server className="w-5 h-5 text-blue-400" />
            </div>
          </div>
          <div className="flex justify-between items-center text-xs text-slate-500">
            <span>v{info?.version ?? "—"}</span>
            <span className="capitalize">{info?.environment ?? "—"}</span>
          </div>
        </div>

        {/* Redis Cache Card */}
        <div className="bg-slate-900 border border-slate-800 rounded-lg p-4 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-16 h-16 bg-red-500/5 rounded-bl-full -mr-4 -mt-4" />
          <div className="flex justify-between items-start mb-4 relative z-10">
            <div>
              <h3 className="text-sm font-medium text-slate-400">Redis Cache Tier</h3>
              <div className="flex items-center gap-2 mt-1">
                <span className="text-2xl font-bold text-slate-100">
                  {redisMemory}
                </span>
              </div>
              <div className="mt-1">
                <StatusBadge status={redisStatus} />
              </div>
            </div>
            <div className="p-2 bg-red-500/10 rounded-md">
              <HardDrive className="w-5 h-5 text-red-400" />
            </div>
          </div>
          <div className="flex justify-between items-center text-xs text-slate-500">
            <span>Clients: {redisClients}</span>
            <span>Allocated Memory</span>
          </div>
        </div>

        {/* PostgreSQL Card — static for now, backend has no DB health endpoint yet */}
        <div className="bg-slate-900 border border-slate-800 rounded-lg p-4 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-16 h-16 bg-indigo-500/5 rounded-bl-full -mr-4 -mt-4" />
          <div className="flex justify-between items-start mb-4 relative z-10">
            <div>
              <h3 className="text-sm font-medium text-slate-400">PostgreSQL DB</h3>
              <div className="flex items-center gap-2 mt-1">
                <span className="text-2xl font-bold text-slate-100">12ms</span>
              </div>
              <div className="mt-1">
                <span className="text-xs font-medium px-1.5 py-0.5 rounded border bg-slate-700/50 text-slate-400 border-slate-700">
                  Not Wired
                </span>
              </div>
            </div>
            <div className="p-2 bg-indigo-500/10 rounded-md">
              <Database className="w-5 h-5 text-indigo-400" />
            </div>
          </div>
          <div className="flex justify-between items-center text-xs text-slate-500">
            <span>RLS Checks: N/A</span>
            <span>Active Pools: N/A</span>
          </div>
        </div>

        {/* Jaeger Exporter Card */}
        <div className="bg-slate-900 border border-slate-800 rounded-lg p-4 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-16 h-16 bg-amber-500/5 rounded-bl-full -mr-4 -mt-4" />
          <div className="flex justify-between items-start mb-4 relative z-10">
            <div>
              <h3 className="text-sm font-medium text-slate-400">OTLP Jaeger Exporter</h3>
              <div className="flex items-center gap-2 mt-1">
                <span className="text-2xl font-bold text-slate-100">
                  {info?.tracing?.exporter?.toUpperCase() ?? "—"}
                </span>
              </div>
              <div className="mt-1">
                <span className={clsx(
                  "text-xs font-medium px-1.5 py-0.5 rounded border",
                  info?.tracing?.enabled
                    ? "bg-emerald-500/10 text-emerald-400 border-emerald-500/20"
                    : "bg-amber-500/10 text-amber-400 border-amber-500/20"
                )}>
                  {info?.tracing?.enabled ? "Enabled" : "Disabled"}
                </span>
              </div>
            </div>
            <div className="p-2 bg-amber-500/10 rounded-md">
              <Box className="w-5 h-5 text-amber-400" />
            </div>
          </div>
          <div className="flex justify-between items-center text-xs text-slate-500">
            <span className="truncate">Target: localhost:4317</span>
            <span className="text-amber-400">OTLP</span>
          </div>
        </div>

      </div>
    </div>
  );
}
